sql:
SELECT DISTINCT equipment_name 
FROM equipment
LIMIT 5;

SELECT process_phase_name 
FROM process_phases 
WHERE process_phase_id IN (
  SELECT DISTINCT process_phase_id 
  FROM process_data 
  WHERE act_force > (
    SELECT AVG(act_force) 
    FROM process_data
  )
);

SELECT setpoint_force
FROM setpoints
WHERE process_phase_id = 200;

SELECT process_phase_id, COUNT(*) AS total_documents
FROM documentation
GROUP BY process_phase_id;

external_knowledge:
- A "heavy load" refers to an actual force greater than 2000; - "significant stretch" indicates an actual shortening greater than 10;
- The "journey (process)" metaphorically represents the process phases in the industrial context;
- "Threshold" and "mark" are used metaphorically to denote the numerical conditions set in the SQL query.

sql:
SELECT DISTINCT process_phase_id
FROM process_phases
ORDER BY process_phase_id ASC;

SELECT setpoint_force
FROM process_data
WHERE process_phase_id = 1 AND equipment_id = 1;
